//+------------------------------------------------------------------+
//|  BreakoutNY_RiskDiagnostic_SP500.mq5                             |
//|  Script diagnóstico de VPP y contrato para SP500 en FundingPips  |
//|  Ejecutar ANTES de cualquier backtest — en cuenta demo/challenge  |
//|  Correr como SCRIPT (no EA) sobre el gráfico SP500/US500/SPX500  |
//+------------------------------------------------------------------+
#property copyright "BreakoutNY Diagnostics — FundingPips 2026"
#property version   "1.00"
#property script_show_inputs true

input double TestRiskUSD   = 50.0;   // Riesgo de prueba en USD
input double TestSL_Points = 5000.0; // SL de prueba en puntos (estimado SP500)

void OnStart()
{
   string sym = Symbol();
   Print("╔══════════════════════════════════════════════════════╗");
   Print("║  BreakoutNY — DIAGNÓSTICO CONTRATO SP500             ║");
   Print("║  Símbolo: ", sym, StringFormat("%*s", 41-StringLen(sym), ""), "║");
   Print("╚══════════════════════════════════════════════════════╝");

   //--- [1] Especificaciones básicas
   double cs  = SymbolInfoDouble(sym, SYMBOL_TRADE_CONTRACT_SIZE);
   double tv  = SymbolInfoDouble(sym, SYMBOL_TRADE_TICK_VALUE);
   double ts  = SymbolInfoDouble(sym, SYMBOL_TRADE_TICK_SIZE);
   double pt  = SymbolInfoDouble(sym, SYMBOL_POINT);
   double bid = SymbolInfoDouble(sym, SYMBOL_BID);
   double ask = SymbolInfoDouble(sym, SYMBOL_ASK);
   int    dig = (int)SymbolInfoInteger(sym, SYMBOL_DIGITS);

   double volMin = SymbolInfoDouble(sym, SYMBOL_VOLUME_MIN);
   double volMax = SymbolInfoDouble(sym, SYMBOL_VOLUME_MAX);
   double volStp = SymbolInfoDouble(sym, SYMBOL_VOLUME_STEP);

   long   execMode = SymbolInfoInteger(sym, SYMBOL_TRADE_EXEMODE);
   string calcMode = "";
   long   cm = SymbolInfoInteger(sym, SYMBOL_TRADE_CALC_MODE);
   if(cm == SYMBOL_CALC_MODE_FOREX)      calcMode = "FOREX";
   else if(cm == SYMBOL_CALC_MODE_CFD)   calcMode = "CFD";
   else if(cm == SYMBOL_CALC_MODE_FUTURES) calcMode = "FUTURES";
   else calcMode = "OTRO(" + (string)cm + ")";

   Print("--- [1] ESPECIFICACIONES DEL CONTRATO ---");
   Print("Símbolo          : ", sym);
   Print("Calc Mode        : ", calcMode, (cm == SYMBOL_CALC_MODE_CFD ? " ← Esperado para índices" : " ⚠ Verificar"));
   Print("ContractSize     : ", cs);
   Print("TickSize         : ", ts, (ts == 0 ? " ← REPORTA 0 (bug broker — normal en FP)" : " ← OK"));
   Print("TickValue        : ", tv, (tv == 0 ? " ← REPORTA 0 (bug broker — NO usar para VPP)" : " ← OK"));
   Print("_Point           : ", pt);
   Print("Digits           : ", dig);
   Print("BID / ASK        : ", DoubleToString(bid,dig), " / ", DoubleToString(ask,dig));
   Print("Spread           : ", DoubleToString((ask-bid)/pt,1), " puntos (", DoubleToString(ask-bid,dig), " precio)");
   Print("VolumeMin        : ", volMin);
   Print("VolumeMax        : ", volMax);
   Print("VolumeStep       : ", volStp);

   //--- [2] Cálculo de VPP — tres métodos
   Print("");
   Print("--- [2] CÁLCULO VPP (Valor Por Punto) ---");

   // Método A: TickValue/TickSize (puede ser 0)
   double vppA = (ts > 0) ? tv / ts : 0.0;
   Print("Método A (TV/TS) : $", (ts > 0 ? DoubleToString(vppA,6) : "N/A — TickSize=0, NO USAR"));

   // Método B: ContractSize × Point (robusto)
   double vppB = cs * pt;
   Print("Método B (CS×pt) : $", DoubleToString(vppB,6), " ← Fórmula robusta (igual que DJI30)");

   // Método C: OrderCalcProfit — VERDAD ABSOLUTA
   double profit100 = 0.0;
   bool okBuy = OrderCalcProfit(ORDER_TYPE_BUY, sym, 1.0,
                                ask, ask + 100.0 * pt, profit100);
   double vppC = okBuy ? profit100 / 100.0 : 0.0;
   Print("Método C (OCP)   : $", (okBuy ? DoubleToString(vppC,6) : "FALLÓ (modo backtest?)"),
         (okBuy ? " ← VERDAD ABSOLUTA" : ""));

   // Determinar VPP final
   double vppFinal = 0.0;
   string vppSource = "";
   if(okBuy && vppC > 0)       { vppFinal = vppC; vppSource = "OrderCalcProfit"; }
   else if(vppB > 0)           { vppFinal = vppB; vppSource = "ContractSize×Point"; }
   else                        { vppFinal = 0;    vppSource = "ERROR — ningún método válido"; }

   Print("VPP FINAL        : $", DoubleToString(vppFinal,6), " (fuente: ", vppSource, ")");

   // Consistencia
   if(okBuy && vppC > 0 && vppB > 0)
   {
      double ratio = vppB / vppC;
      if(MathAbs(ratio - 1.0) < 0.02)
         Print("✓ Fórmula B confirmada — diferencia < 2%");
      else
         Print("⚠ DISCREPANCIA: B=", DoubleToString(vppB,6), " vs C=", DoubleToString(vppC,6),
               " (ratio=", DoubleToString(ratio,4), ") — Usar Método C");
   }

   //--- [3] Comparativa con DJI30
   Print("");
   Print("--- [3] COMPARATIVA DJI30 vs SP500 ---");
   Print("DJI30: CS=5.0 | pt=0.01 | VPP=$0.05 | SL típico=12000pts → $600/lot");
   Print("SP500: CS=", cs, " | pt=", pt, " | VPP=$", DoubleToString(vppFinal,6));
   if(vppFinal > 0)
   {
      double ratioVPP = (0.05 > 0) ? vppFinal / 0.05 : 0;
      Print("Ratio VPP (SP500/DJI30): ", DoubleToString(ratioVPP,3), "×");
      double estimatedSP500SL = 12000.0 * 0.05 / vppFinal; // mismo riesgo nominal
      Print("SL equivalente a DJI30 $600: ~", DoubleToString(estimatedSP500SL,0), " pts SP500");
   }

   //--- [4] Cálculo de lotaje con el riesgo configurado
   Print("");
   Print("--- [4] LOTAJE PARA RISK=$", TestRiskUSD, " | SL=", TestSL_Points, " pts ---");

   if(vppFinal > 0)
   {
      double lotsRaw = TestRiskUSD / (TestSL_Points * vppFinal);
      double lots    = MathRound(lotsRaw / volStp) * volStp;
      lots = MathMax(volMin, MathMin(volMax, lots));
      lots = NormalizeDouble(lots, 2);

      Print("Cálculo: $", TestRiskUSD, " / (", TestSL_Points, " pts × $", DoubleToString(vppFinal,6), ")");
      Print("         = ", DoubleToString(lotsRaw,4), " lotes (raw)");
      Print("         = ", lots, " lotes (normalizado)");

      // Verificar con OrderCalcProfit
      if(okBuy && lots > 0)
      {
         double verifyProfit = 0.0;
         bool okV = OrderCalcProfit(ORDER_TYPE_BUY, sym, lots,
                                    ask, ask - TestSL_Points * pt, verifyProfit);
         if(okV)
            Print("✓ Verificación pérdida en SL: $", DoubleToString(-verifyProfit,2),
                  " (objetivo: $", TestRiskUSD, ")");

         // Rango de SL para calibración
         Print("");
         Print("--- [5] RANGOS DE SL A CALIBRAR ---");
         double slValues[] = {2000, 3000, 4000, 5000, 6000, 7000, 8000, 10000, 12000};
         for(int i = 0; i < ArraySize(slValues); i++)
         {
            double sl_i = slValues[i];
            double lr_i = TestRiskUSD / (sl_i * vppFinal);
            double l_i  = MathRound(lr_i / volStp) * volStp;
            l_i = MathMax(volMin, MathMin(volMax, l_i));
            Print("SL=", (int)sl_i, " pts → Lotes=", NormalizeDouble(l_i,2),
                  " | Riesgo/lot=$", DoubleToString(sl_i * vppFinal,2));
         }
      }
   }
   else
      Print("❌ VPP=0 — No se puede calcular lotaje. Verificar símbolo.");

   //--- [6] Estimación rangos SP500 pre-NY
   Print("");
   Print("--- [6] ESTIMACIÓN RANGOS PRE-NY SP500 ---");
   Print("Nota: Valores iniciales estimados para calibrador.");
   Print("SP500 (~5500 pts) vs DJI30 (~42000 pts) → ratio ~0.13");
   Print("DJI30 MinSL=8200 pts → SP500 estimado MinSL: ~1000-1500 pts");
   Print("DJI30 MaxSL=20000 pts → SP500 estimado MaxSL: ~2600-3000 pts");
   Print("⚠ OBLIGATORIO correr BreakoutNY_Calibrator_SP500.mq5 para P25/P75 reales");
   Print("⚠ Los valores MinSL_Points/MaxSL_Points del EA están en puntos del símbolo");
   Print("  SP500 pt=", pt, " → SL de 1500 pts = ", DoubleToString(1500*pt,dig), " en precio");

   //--- [7] Spread impact
   Print("");
   Print("--- [7] IMPACTO DEL SPREAD ---");
   double spread_pts = (ask - bid) / pt;
   Print("Spread actual: ", DoubleToString(spread_pts,1), " puntos");
   if(vppFinal > 0)
   {
      double spreadCost = spread_pts * vppFinal; // por lote
      Print("Costo spread por lote: $", DoubleToString(spreadCost,4));
      Print("Spread como % de MinSL (3000 pts): ", DoubleToString(spread_pts/3000.0*100,2), "%");
   }

   //--- [8] Hold time — advertencia clave
   Print("");
   Print("--- [8] RECORDATORIO SessionCloseHour ---");
   Print("SessionCloseHour = 17 (17:00 UTC) — NUNCA CAMBIAR");
   Print("SP500 cierre NYSE = 21:00 UTC — EA cierra antes de las 17:00 UTC");
   Print("Hold máximo esperado: ~2h 05min (14:50 → 17:00 UTC)");
   Print("Si hold > 2h 10min en backtest → BUG en SessionCloseHour");

   //--- Resumen final
   Print("");
   Print("╔══════════════════════════════════════════════════════╗");
   Print("║  RESUMEN PARA EA BreakoutNY_v1_SP500_FP.mq5         ║");
   Print("╠══════════════════════════════════════════════════════╣");
   Print("║  Símbolo     : ", sym, StringFormat("%*s", 39-StringLen(sym), ""), "║");
   Print("║  VPP         : $", StringFormat("%-38s", DoubleToString(vppFinal,6)), "║");
   Print("║  VolumeMin   : ", StringFormat("%-39s", (string)volMin), "║");
   Print("║  VolumeStep  : ", StringFormat("%-39s", (string)volStp), "║");
   Print("║  Fórmula VPP : ContractSize × Point (Fórmula B)     ║");
   Print("║  ACCIÓN      : Correr calibrador para MinSL/MaxSL   ║");
   Print("╚══════════════════════════════════════════════════════╝");
}
