cat > /home/claude/BreakoutNY_Calibrator_SP500.mq5 << 'MQLEOF'
//+------------------------------------------------------------------+
//|  BreakoutNY_Calibrator_SP500.mq5                                 |
//|  Script calibrador de rangos históricos pre-NY para SP500        |
//|  Correr sobre historial M5 2021-2024 (In-Sample)                 |
//|  Objetivo: obtener P25, P50, P75, P90 del rango de las 3 velas  |
//|  OBLIGATORIO antes de optimizar el EA                            |
//+------------------------------------------------------------------+
#property copyright "BreakoutNY Calibrator SP500 — FundingPips 2026"
#property version   "1.00"
#property script_show_inputs true

input datetime StartDate  = D'2021.01.01'; // Inicio del período de análisis (IS)
input datetime EndDate    = D'2024.12.31'; // Fin del período de análisis (IS)
input int      OffsetHours = 2;            // UTC offset servidor FP (UTC+2)
input bool     ExportCSV  = true;          // Exportar datos diarios a CSV

// Horas de las 3 velas en hora SERVIDOR (UTC+2)
// 14:35 UTC = 16:35 srv | 14:40 UTC = 16:40 srv | 14:45 UTC = 16:45 srv
// La barra de entrada es 14:50 UTC = 16:50 srv (índice 0 cuando calculamos)

void OnStart()
{
   Print("=== BreakoutNY Calibrator SP500 ===");
   Print("Símbolo  : ", Symbol());
   Print("Período  : ", TimeToString(StartDate, TIME_DATE), " → ", TimeToString(EndDate, TIME_DATE));
   Print("Offset   : UTC+", OffsetHours);

   double pt = SymbolInfoDouble(Symbol(), SYMBOL_POINT);

   // Hora servidor de la primera vela del rango = 14:35 UTC + offset
   int srv_h = (14 + OffsetHours) % 24; // 16 para UTC+2
   int srv_m = 35;

   // Colectar todos los rangos diarios
   double ranges[];       // rangos en puntos
   int    dows[];         // día de semana
   string dates[];        // fecha
   int    count = 0;

   // Recorrer barras M5 en el período
   int totalBars = Bars(Symbol(), PERIOD_M5, StartDate, EndDate);
   if(totalBars < 100)
   {
      Print("❌ Historial insuficiente: ", totalBars, " barras M5. Descargar más datos.");
      return;
   }
   Print("Barras M5 en período: ", totalBars);

   // Obtener arrays de tiempo, high, low
   datetime timeArr[];
   double   highArr[], lowArr[];
   ArraySetAsSeries(timeArr, false);
   ArraySetAsSeries(highArr, false);
   ArraySetAsSeries(lowArr,  false);

   int copied = CopyTime(Symbol(), PERIOD_M5, StartDate, EndDate, timeArr);
   CopyHigh(Symbol(), PERIOD_M5, StartDate, EndDate, highArr);
   CopyLow(Symbol(), PERIOD_M5, StartDate, EndDate, lowArr);

   if(copied < 100)
   {
      Print("❌ Error copiando datos: ", copied, " barras");
      return;
   }

   ArrayResize(ranges, 1000);
   ArrayResize(dows,   1000);
   ArrayResize(dates,  1000);

   // Iterar buscando las barras de 14:35 srv (índice 0 del rango)
   for(int i = 0; i < copied - 4; i++)
   {
      MqlDateTime dt;
      TimeToStruct(timeArr[i], dt);

      // Buscar la barra de las 14:35 servidor (srv_h:35)
      if(dt.hour != srv_h || dt.min != srv_m) continue;
      if(dt.day_of_week == 0 || dt.day_of_week == 6) continue; // fin de semana

      // Verificar que tenemos las 3 barras consecutivas (14:35, 14:40, 14:45)
      if(i + 2 >= copied) break;

      MqlDateTime dt1, dt2;
      TimeToStruct(timeArr[i+1], dt1);
      TimeToStruct(timeArr[i+2], dt2);

      // Las 3 barras deben ser consecutivas y del mismo día
      if(dt1.hour != srv_h || dt1.min != 40) continue;
      if(dt2.hour != srv_h || dt2.min != 45) continue;
      if(dt1.day != dt.day || dt2.day != dt.day) continue;

      // Calcular rango de las 3 velas
      double rHigh = MathMax(highArr[i], MathMax(highArr[i+1], highArr[i+2]));
      double rLow  = MathMin(lowArr[i],  MathMin(lowArr[i+1], lowArr[i+2]));
      double rangePts = (rHigh - rLow) / pt;

      if(rangePts <= 0) continue;

      // Guardar
      if(count >= ArraySize(ranges))
      {
         ArrayResize(ranges, count + 500);
         ArrayResize(dows,   count + 500);
         ArrayResize(dates,  count + 500);
      }

      ranges[count] = rangePts;
      dows[count]   = dt.day_of_week;
      dates[count]  = StringFormat("%04d.%02d.%02d", dt.year, dt.mon, dt.day);
      count++;
   }

   if(count < 20)
   {
      Print("❌ Muy pocos días válidos: ", count, ". Verificar offset y símbolo.");
      return;
   }

   ArrayResize(ranges, count);
   ArrayResize(dows,   count);
   ArrayResize(dates,  count);

   Print("✓ Días válidos encontrados: ", count);

   // Ordenar rangos para percentiles
   double sortedRanges[];
   ArrayCopy(sortedRanges, ranges);
   ArraySort(sortedRanges);

   // Calcular percentiles
   double p10  = sortedRanges[(int)(count * 0.10)];
   double p25  = sortedRanges[(int)(count * 0.25)];
   double p50  = sortedRanges[(int)(count * 0.50)];
   double p75  = sortedRanges[(int)(count * 0.75)];
   double p90  = sortedRanges[(int)(count * 0.90)];
   double p95  = sortedRanges[(int)(count * 0.95)];
   double pMin = sortedRanges[0];
   double pMax = sortedRanges[count-1];

   double sumR = 0; for(int i=0;i<count;i++) sumR += ranges[i];
   double avgR = sumR / count;

   Print("=== DISTRIBUCIÓN DEL RANGO (puntos) ===");
   Print("N días      : ", count);
   Print("Mínimo      : ", DoubleToString(pMin,1), " pts");
   Print("P10         : ", DoubleToString(p10,1), " pts");
   Print("P25         : ", DoubleToString(p25,1), " pts  ← MinSL_Points sugerido");
   Print("P50 (Mediana): ", DoubleToString(p50,1), " pts");
   Print("Media       : ", DoubleToString(avgR,1), " pts");
   Print("P75         : ", DoubleToString(p75,1), " pts  ← MaxSL_Points sugerido (conservador)");
   Print("P90         : ", DoubleToString(p90,1), " pts  ← MaxSL_Points sugerido (amplio)");
   Print("P95         : ", DoubleToString(p95,1), " pts");
   Print("Máximo      : ", DoubleToString(pMax,1), " pts");

   // Análisis por día de semana
   Print("");
   Print("=== DISTRIBUCIÓN POR DÍA DE SEMANA ===");
   string dayNames[] = {"Dom", "Lun", "Mar", "Mie", "Jue", "Vie", "Sab"};
   for(int d = 1; d <= 5; d++)
   {
      int dayCount = 0;
      double daySum = 0, dayMin = 1e9, dayMax = 0;
      double dayRanges[];
      ArrayResize(dayRanges, 300);
      int dc2 = 0;
      for(int i = 0; i < count; i++)
      {
         if(dows[i] == d)
         {
            dayRanges[dc2++] = ranges[i];
            daySum += ranges[i];
            if(ranges[i] < dayMin) dayMin = ranges[i];
            if(ranges[i] > dayMax) dayMax = ranges[i];
            dayCount++;
         }
      }
      if(dayCount < 5) continue;
      ArrayResize(dayRanges, dc2);
      ArraySort(dayRanges);
      double dayP25 = dayRanges[(int)(dc2*0.25)];
      double dayP75 = dayRanges[(int)(dc2*0.75)];
      double dayAvg = daySum / dayCount;
      Print(dayNames[d], ": N=", dayCount,
            " | Avg=", DoubleToString(dayAvg,1),
            " | P25=", DoubleToString(dayP25,1),
            " | P75=", DoubleToString(dayP75,1),
            " | [", DoubleToString(dayMin,1), "-", DoubleToString(dayMax,1), "]");
   }

   // Rangos filtrados (entre P25 y P90)
   int filtP25P90 = 0;
   for(int i = 0; i < count; i++)
      if(ranges[i] >= p25 && ranges[i] <= p90) filtP25P90++;
   Print("");
   Print("Días entre P25-P90: ", filtP25P90, "/", count, " (",
         DoubleToString(100.0*filtP25P90/count,1), "%) → días que operaría el EA");

   // Comparativa DJI30
   Print("");
   Print("=== COMPARATIVA CON DJI30 ===");
   Print("DJI30 P25=8200 pts, P75=20000 pts, Media=~13000 pts");
   Print("SP500 P25=", DoubleToString(p25,1), " pts, P75=", DoubleToString(p75,1),
         " pts, Media=", DoubleToString(avgR,1), " pts");
   if(avgR > 0 && 13000 > 0)
      Print("Ratio SP500/DJI30: ", DoubleToString(avgR/13000.0,3), "×");

   // Recomendación final
   Print("");
   Print("╔══════════════════════════════════════════════════════╗");
   Print("║  VALORES RECOMENDADOS PARA EA (verificar con        ║");
   Print("║  backtest IS 2021-2024 antes de usar en producción) ║");
   Print("╠══════════════════════════════════════════════════════╣");
   Print("║  MinSL_Points = ", StringFormat("%-38s", DoubleToString(p25,0)), "║");
   Print("║  MaxSL_Points = ", StringFormat("%-38s", DoubleToString(p90,0)), "║");
   Print("║  (P25 como MinSL, P90 como MaxSL — optimizar luego) ║");
   Print("╚══════════════════════════════════════════════════════╝");

   // Exportar CSV
   if(ExportCSV)
   {
      string csvName = StringFormat("BreakoutNY_Calibrator_SP500_%s_%s.csv",
                       TimeToString(StartDate, TIME_DATE),
                       TimeToString(EndDate, TIME_DATE));
      StringReplace(csvName, ".", "-");
      StringReplace(csvName, " ", "_");

      int fh = FileOpen(csvName, FILE_WRITE|FILE_CSV|FILE_ANSI, ',');
      if(fh != INVALID_HANDLE)
      {
         FileWrite(fh, "Date", "DOW", "Range_Pts", "Range_Price",
                   "InP25_P90", "Note");
         for(int i = 0; i < count; i++)
         {
            bool inFilter = (ranges[i] >= p25 && ranges[i] <= p90);
            string note = "";
            if(ranges[i] < p25) note = "BELOW_P25";
            else if(ranges[i] > p90) note = "ABOVE_P90";
            else note = "OK";
            FileWrite(fh, dates[i], dayNames[dows[i]],
                      DoubleToString(ranges[i],1),
                      DoubleToString(ranges[i]*pt,4),
                      (inFilter?"YES":"NO"),
                      note);
         }
         FileClose(fh);
         Print("✓ CSV exportado: ", csvName);
      }
   }

   Print("=== Calibración completada ===");
}
MQLEOF

echo "Calibrador creado: $(wc -l < /home/claude/BreakoutNY_Calibrator_SP500.mq5) líneas"

