  return new TableCell({
    borders: isHeader ? thBorders : borders,
    columnSpan: colSpan,
    width: { size: 0, type: WidthType.AUTO },
    shading: isHeader
      ? { fill: "1F4E79", type: ShadingType.CLEAR }
