input int     ATR_Period         = 14;
input double  ATR_MaxMultiplier  = 2.0;
input double  ATR_MinMultiplier  = 0.3;
input int     ATR_BaselineDays   = 20;

//=== MISC ===============================================================
input group   "=== MISC ==="
input bool    EnableCSV          = true;
input string  CSVFileName        = "BreakoutNY_v1_SP500_trades";
input int     MagicNumber        = 202403;  // SP500=202403 · DJI30=202402 · NAS100=202401

//=== VISUAL =============================================================
input group "=== VISUAL ==="
